import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';

const TopHeader = ({ onLogout }) => {  // ✅ Receive onLogout prop
  const [showUserMenu, setShowUserMenu] = useState(false);
  const navigate = useNavigate();

  // ✅ Get user info
  const userEmail = localStorage.getItem('user') || sessionStorage.getItem('user') || 'Demo User';
  const token = localStorage.getItem('token') || sessionStorage.getItem('token');
  const isDemoUser = token === 'FAKE_TOKEN_123';

  // ✅ Handle logout
  const handleLogout = () => {
    console.log('🚪 Logging out...');
    
    // Clear all authentication data
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    sessionStorage.removeItem('token');
    sessionStorage.removeItem('user');
    
    // Call parent logout handler
    if (onLogout) {
      onLogout();
    }
    
    // Navigate to login page
    navigate('/login');
  };

  // ✅ Handle user profile
  const handleUserProfile = () => {
    setShowUserMenu(false);
    alert(`User Profile\n\nEmail: ${userEmail}\nAccount Type: ${isDemoUser ? 'Demo Account' : 'Regular Account'}`);
  };

  return (
    <header className="bg-white shadow-sm border-b px-6 py-4">
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-bold text-gray-800">
          NeuroFleetX Dashboard
        </h2>
        
        {/* ✅ User Menu Section */}
        <div className="relative">
          <div className="flex items-center space-x-4">
            
            {/* ✅ User Profile Button */}
            <button
              onClick={() => setShowUserMenu(!showUserMenu)}
              className="flex items-center space-x-3 px-4 py-2 rounded-lg hover:bg-gray-100 transition-colors"
            >
              {/* User Avatar */}
              <div className="w-9 h-9 bg-blue-500 rounded-full flex items-center justify-center text-white text-sm font-bold">
                {userEmail.charAt(0).toUpperCase()}
              </div>
              
              {/* User Name */}
              <div className="text-left">
                <div className="text-sm font-medium text-gray-700">
                  {isDemoUser ? '👤 Demo User' : userEmail.split('@')[0]}
                </div>
                <div className="text-xs text-gray-500">
                  {isDemoUser ? 'Demo Account' : 'User Account'}
                </div>
              </div>
              
              {/* Dropdown Arrow */}
              <svg 
                className={`w-4 h-4 text-gray-400 transition-transform ${showUserMenu ? 'rotate-180' : ''}`} 
                fill="none" 
                stroke="currentColor" 
                viewBox="0 0 24 24"
              >
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
              </svg>
            </button>

            {/* ✅ Logout Button */}
            <button
              onClick={handleLogout}
              className="px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 transition-colors text-sm font-medium flex items-center space-x-2"
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" />
              </svg>
              <span>Logout</span>
            </button>
          </div>

          {/* ✅ User Dropdown Menu */}
          {showUserMenu && (
            <div className="absolute right-0 mt-2 w-56 bg-white rounded-lg shadow-lg border border-gray-200 py-2 z-50">
              
              {/* Profile Info */}
              <div className="px-4 py-3 border-b border-gray-100">
                <div className="text-sm font-medium text-gray-900">{userEmail}</div>
                <div className="text-xs text-gray-500">
                  {isDemoUser ? 'Demo Account - All Features Enabled' : 'Regular User Account'}
                </div>
              </div>

              {/* User Profile Option */}
              <button
                onClick={handleUserProfile}
                className="flex items-center w-full px-4 py-2 text-sm text-gray-700 hover:bg-gray-100 transition-colors"
              >
                <svg className="w-4 h-4 mr-3 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" />
                </svg>
                View Profile
              </button>
              
              {/* Divider */}
              <div className="border-t border-gray-100 my-1"></div>
              
              {/* Logout from Dropdown */}
              <button
                onClick={handleLogout}
                className="flex items-center w-full px-4 py-2 text-sm text-red-600 hover:bg-red-50 transition-colors"
              >
                <svg className="w-4 h-4 mr-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" />
                </svg>
                Sign Out
              </button>
            </div>
          )}
        </div>
      </div>

      {/* ✅ Demo Mode Banner (if demo user) */}
      {isDemoUser && (
        <div className="mt-3 bg-green-100 border-l-4 border-green-500 p-3 rounded">
          <div className="flex items-center">
            <span className="text-green-600 mr-2">ℹ️</span>
            <p className="text-sm text-green-700">
              <strong>Demo Mode:</strong> You're using the demo version with full access to all features!
            </p>
          </div>
        </div>
      )}
    </header>
  );
};

export default TopHeader;
